/// Fold: fcmp pred (select (fcmp oge x, 0.0), x, (fneg x)), 0.0
///   into fcmp pred x, 0.0
/// This pattern is equivalent to fabs(x), and fabs(x) ==/!= 0.0 --> x ==/!= 0.0
static Instruction *foldFCmpSelectFabsZero(FCmpInst &I) {
  Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1);

  // Match fcmp with zero
  if (!match(Op1, m_AnyZeroFP()))
    return nullptr;

  // Match select on Op0
  Value *Cond, *TrueVal, *FalseVal;
  if (!match(Op0, m_Select(m_Value(Cond), m_Value(TrueVal), m_Value(FalseVal))))
    return nullptr;

  // Match the condition as fcmp X, 0.0
  Value *X;
  FCmpInst::Predicate Pred;
  if (!match(Cond, m_FCmp(Pred, m_Value(X), m_AnyZeroFP())))
    return nullptr;

  // Check if this forms an fabs pattern:
  // (X >= 0.0) ? X : (fneg X)  or  (X > 0.0) ? X : (fneg X)
  // (X <  0.0) ? X : (fneg X)  or  (X <= 0.0) ? X : (fneg X) - swapped
  // (X <= 0.0) ? (fneg X) : X  or  (X < 0.0) ? (fneg X) : X
  // (X >  0.0) ? (fneg X) : X  or  (X >= 0.0) ? (fneg X) : X - swapped
  auto IsFNeg = [](Value *V, Value *OfX) {
    return match(V, m_FNeg(m_Specific(OfX)));
  };

  // Pattern: (cond ? X : fneg(X))  or  (cond ? fneg(X) : X)
  bool HasFabsPattern =
      (TrueVal == X && IsFNeg(FalseVal, X)) ||
      (FalseVal == X && IsFNeg(TrueVal, X));

  if (!HasFabsPattern)
    return nullptr;

  // fabs(X) == 0.0 --> X == 0.0
  // fabs(X) != 0.0 --> X != 0.0
  // fabs(X) > 0.0 --> X != 0.0
  // fabs(X) <= 0.0 --> X == 0.0 (plus NaN check)
  // etc.
  // The sign of zero doesn't matter for fcmp, so we can replace
  // fabs(X) with X for this comparison.
  auto *NewFCmp = new FCmpInst(I.getPredicate(), X, Op1, "", &I);
  NewFCmp->setFastMathFlags(I.getFastMathFlags());
  return NewFCmp;
}

